/**
 * Classifica o tipo de follow-up a partir da etapa atual da tarefa
 * e dos atributos. Reconhece tanto o funil principal (vendas/renovação)
 * quanto o funil paralelo de Sinistros.
 *
 * Lê de "Carregar tarefa" (kanbanTask.get) que vem antes — assim temos
 * o objeto completo (board.steps, custom_attributes, conversations etc).
 *
 * IMPORTANTE: usa conversation.display_id (não conversation.id) porque
 * sendMessage downstream invoca a API REST do Chatwoot que aceita
 * display_id, não o id interno.
 */
const task = $input.first().json;

const accountId = task.account_id ?? task.account?.id;
const boardSteps = task.board?.steps ?? task.board?.steps_summary ?? [];
const currentStep = boardSteps.find(s => s.id === task.board_step_id);
const stepName = (currentStep?.name ?? '').toLowerCase();
const boardName = (task.board?.name ?? '').toLowerCase();
const conversation = (task.conversations ?? [])[0] ?? task.conversation ?? {};
const contact = conversation.meta?.sender ?? conversation.contact ?? task.contact ?? (task.contacts ?? [])[0] ?? {};
const contactPhone = contact.phone_number
  || contact.additional_attributes?.social_profiles?.instagram
  || `task-${task.id}`;
const customAttrs = task.custom_attributes ?? {};

const dataRenovacao = customAttrs.data_renovacao;
let diasParaRenovacao = null;
if (dataRenovacao) {
  const d = DateTime.fromISO(String(dataRenovacao));
  if (d.isValid) {
    diasParaRenovacao = Math.ceil(d.diff(DateTime.now(), 'days').days);
  }
}

let tipo;
if (boardName === 'sinistros') {
  if (['aberto', 'documentação', 'documentacao'].includes(stepName)) {
    tipo = 'sinistro_documentacao';
  } else if (['em análise', 'em analise'].includes(stepName)) {
    tipo = 'sinistro_analise';
  } else if (['perícia / vistoria', 'pericia / vistoria'].includes(stepName)) {
    tipo = 'sinistro_pericia';
  } else {
    tipo = 'ignorar';
  }
} else if (stepName === 'renovação' || stepName === 'renovacao' ||
           (diasParaRenovacao !== null && diasParaRenovacao <= 30 && diasParaRenovacao >= 0 && stepName === 'assinada')) {
  tipo = 'renovacao';
} else if (['aprovada', 'apólice emitida', 'apolice emitida'].includes(stepName)) {
  tipo = 'pagamento_pendente';
} else if (['novo lead', 'cotação solicitada', 'cotacao solicitada', 'proposta enviada'].includes(stepName)) {
  tipo = 'pre_venda';
} else {
  tipo = 'ignorar';
}

return [{
  json: {
    tipo_followup: tipo,
    task_id: task.id,
    task_title: task.title,
    task_description: task.description ?? '',
    board_id: task.board?.id,
    board_name: boardName,
    step_name: stepName,
    step_id: task.board_step_id,
    account_id: accountId,
    conversation_id: conversation.display_id ?? conversation.id,
    conversation_internal_id: conversation.id,
    inbox_id: conversation.inbox?.id ?? conversation.inbox_id,
    contact_id: contact.id ?? (task.contact_ids ?? [])[0],
    contact_name: contact.name,
    contact_phone: contactPhone,
    operadora: customAttrs.operadora,
    plano: customAttrs.plano_escolhido,
    numero_apolice: customAttrs.numero_apolice,
    numero_sinistro: customAttrs.numero_sinistro,
    tipo_sinistro: customAttrs.tipo_sinistro,
    data_renovacao: dataRenovacao,
    dias_para_renovacao: diasParaRenovacao
  }
}];
